const select=document.getElementById('nucleoSelect'), customSelect=document.getElementById('customSelect'), customSelectBtn=document.getElementById('customSelectBtn'), customSelectMenu=document.getElementById('customSelectMenu'), nav=document.getElementById('nav'), content=document.getElementById('content'), pageTitle=document.getElementById('pageTitle'), pageDesc=document.getElementById('pageDesc'), activeBadge=document.getElementById('activeBadge'), tooltip=document.getElementById('tooltip'), chartModal=document.getElementById('chartModal'), modalTitle=document.getElementById('modalTitle'), modalSubtitle=document.getElementById('modalSubtitle'), modalCanvas=document.getElementById('modalCanvas'), closeModal=document.getElementById('closeModal');
let currentViewKey = 'geral';
let menuBaseEventsBound = false;
const fmt = new Intl.NumberFormat('pt-BR');
const brMoney = new Intl.NumberFormat('pt-BR', {style:'currency', currency:'BRL'});
const brPercent = new Intl.NumberFormat('pt-BR', {style:'percent', minimumFractionDigits:2, maximumFractionDigits:2});
const shortFmt = new Intl.NumberFormat('pt-BR', {notation:'compact', maximumFractionDigits:1});
function esc(s){ return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m])); }
function kpiCard(label,value,sub,extra=''){return `<div class="kpi"><div class="label">${esc(label)}</div><div class="value">${fmt.format(Math.round(+value||0))}</div><div class="sub">${esc(sub||'')}</div>${extra||''}</div>`}
function pct(v){ return (v||0).toFixed(1).replace('.',',')+'%'; }
function rateBadge(value, label, goodWhen='above'){
 const cls = goodWhen==='below' ? (value<=10?'good':'warn') : (value>=90?'good':'warn');
 return `<div class="kpiRate ${cls}">${pct(value)} · ${esc(label)}</div>${goodWhen==='above'?'<span class="kpiGoal">Meta mínima: 90% atendidas</span>':''}`;
}
function kpisForChannel(channel){
 const of=+channel.ofertadas||0, at=+channel.atendidas||0, ab=+channel.abandonadas||0, cb=+channel.callback||0;
 const atPct=of?at/of*100:0, abPct=of?ab/of*100:0;
 const cbCard = cb>0 ? kpiCard(labels.callback,cb,'Retornos registrados na fila do núcleo') : '';
 return `${kpiCard(labels.ofertadas,of,'Chamadas recebidas no período')}${kpiCard(labels.atendidas,at,'Chamadas efetivamente atendidas',rateBadge(atPct,'atendidas','above'))}${kpiCard(labels.abandonadas,ab,'Chamadas abandonadas',rateBadge(abPct,'abandonadas','below'))}${cbCard}${kpiCard(labels.whatsapp,channel.whatsapp||0,'Tickets via WhatsApp')}`;
}
