 return `<section class="tableCard"><div class="tableHead"><div><h4>Tabela Executiva · Top Filiais</h4><p>Ranking de filiais disponível na aba Assistência, com participação sobre o total apresentado.</p></div><div class="chartTotal">Total: ${fmt.format(Math.round(total))}</div></div><table class="executiveTable"><thead><tr><th>Rank</th><th>Filial</th><th>Qtd.</th><th>Part.</th></tr></thead><tbody>${rows}</tbody></table></section>`;
