 return `<section class="tableCard"><div class="tableHead"><div><h4>Tabela Executiva · Top 20 Marcas</h4><p>Ranking por marca na Assistência, com os IDs removidos para deixar a leitura mais limpa e executiva.</p></div><div class="chartActions"><div class="chartTotal">O.S: ${fmt.format(totalOS)}</div><div class="chartTotal">Vendas: ${fmt.format(totalVendas)}</div></div></div><div class="tableCaption">Faturamento total apresentado: <strong>${brMoney.format(totalFaturamento)}</strong> · Custo médio de O.S somado: <strong>${brMoney.format(totalCusto)}</strong></div><div class="tableScroll"><table class="executiveTable brandTable"><thead><tr><th>Marca</th><th>Quantidade de O.S</th><th>Quantidade de Vendas</th><th>Qtde. O.S por Faturamento</th><th>Custo Médio de O.S</th><th>Faturamento</th><th>Custo O.S por Faturamento</th></tr></thead><tbody>${rows}</tbody></table></div></section>`;
