function polarToCartesian(cx, cy, r, angle){ const rad=(angle-90)*Math.PI/180; return {x:cx + r*Math.cos(rad), y:cy + r*Math.sin(rad)}; }
function donutPath(cx, cy, rOuter, rInner, startAngle, endAngle){
 const startOuter=polarToCartesian(cx,cy,rOuter,endAngle), endOuter=polarToCartesian(cx,cy,rOuter,startAngle);
 const startInner=polarToCartesian(cx,cy,rInner,startAngle), endInner=polarToCartesian(cx,cy,rInner,endAngle);
 const largeArc=endAngle-startAngle<=180?0:1;
 return `M ${startOuter.x} ${startOuter.y} A ${rOuter} ${rOuter} 0 ${largeArc} 0 ${endOuter.x} ${endOuter.y} L ${startInner.x} ${startInner.y} A ${rInner} ${rInner} 0 ${largeArc} 1 ${endInner.x} ${endInner.y} Z`;
}
function pieChart(el,data,expanded=false){
 const rows=(data||[]).map(d=>({label:String(d.label||''), value:+d.value||0})).filter(d=>d.value>0);
 const total=rows.reduce((a,d)=>a+d.value,0);
 if(!rows.length || total<=0){ el.innerHTML='<div class="empty"><strong>Sem dados</strong>Não há valores disponíveis para este gráfico.</div>'; return; }
 const colors=['#0057B8','#0072CE','#00A3FF','#4FB7FF','#8CCFFF','#244E85','#5A9BE2','#3E7CC3'];
 const size=expanded?380:340, cx=size/2, cy=size/2, rOuter=expanded?128:116, rInner=expanded?74:66;
 let start=-90;
 const slices=rows.map((d,i)=>{ const pct=d.value/total; const angle=Math.max(pct*360,0.6); const end=start+angle; const mid=start+angle/2; const path=donutPath(cx,cy,rOuter,rInner,start,end); const labelPos=polarToCartesian(cx,cy,(rOuter+rInner)/2 + (expanded?2:0),mid); const obj={...d,pct,angle,start,end,mid,path,color:colors[i%colors.length],labelPos}; start=end; return obj; });
 let svg=`<svg class="pieSvg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}" role="img" aria-label="Gráfico de pizza"><defs><filter id="pieShadow"><feDropShadow dx="0" dy="10" stdDeviation="10" flood-color="#0057B8" flood-opacity=".15"/></filter></defs>`;
 svg += `<circle cx="${cx}" cy="${cy}" r="${rOuter+8}" fill="#F4FAFF"/>`;
 slices.forEach((s,i)=>{ const tip=`${s.label}: ${fmt.format(Math.round(s.value))} (${(s.pct*100).toFixed(1).replace('.',',')}%)`; svg += `<path class="bar" data-tip="${esc(tip)}" d="${s.path}" fill="${s.color}" filter="url(#pieShadow)" stroke="#FFFFFF" stroke-width="4" stroke-linejoin="round"></path>`; if(s.pct>=0.09){ svg += `<text class="sliceLabel" x="${s.labelPos.x}" y="${s.labelPos.y}" text-anchor="middle" dominant-baseline="middle">${Math.round(s.pct*100)}%</text>`; }});
 svg += `</svg>`;
 const legend=slices.map((s,i)=>`<div class="pieLegendItem bar" data-tip="${esc(s.label)}: ${fmt.format(Math.round(s.value))} (${(s.pct*100).toFixed(1).replace('.',',')}%)"><span class="pieSwatch" style="background:${s.color}"></span><div class="pieLegendText"><strong>${esc(s.label)}</strong><small>${(s.pct*100).toFixed(1).replace('.',',')}% do total</small></div><div class="pieLegendValue"><strong>${fmt.format(Math.round(s.value))}</strong><small>${i+1}º item</small></div></div>`).join('');
 const isPesquisaStatus = rows.some(r=>String(r.label).toLowerCase().includes('finalizada')) && rows.some(r=>String(r.label).toLowerCase().includes('andamento'));
 const centerSmall = isPesquisaStatus ? 'Solicitadas' : 'Total';
 const centerFoot = isPesquisaStatus ? 'pesquisas' : `${rows.length} categoria${rows.length>1?'s':''}`;
 el.innerHTML=`<div class="pieWrap"><div class="pieVisual">${svg}<div class="pieCenter"><small>${centerSmall}</small><strong>${fmt.format(Math.round(total))}</strong><span>${centerFoot}</span></div></div><div class="pieLegend">${legend}</div></div>`;
 bindTips(el);
}

function barChart(el,data){
 const W=el.clientWidth||980,H=Math.max(el.clientHeight||360, 120 + (data||[]).length*34); const m={t:18,r:86,b:26,l:260}; const max=Math.max(...data.map(d=>+d.value||0),1); let svg=`<svg viewBox="0 0 ${W} ${H}" width="100%" height="100%" role="img">`;
 svg += `<defs><linearGradient id="barGrad" x1="0" x2="1"><stop offset="0" stop-color="#0057B8"/><stop offset="1" stop-color="#00A3FF"/></linearGradient><filter id="softShadow"><feDropShadow dx="0" dy="3" stdDeviation="3" flood-color="#0057B8" flood-opacity=".18"/></filter></defs>`;
 const gap=11; const bh=Math.max(17,(H-m.t-m.b-(data.length-1)*gap)/data.length);
 data.forEach((d,i)=>{ const y=m.t+i*(bh+gap); const w=(W-m.l-m.r)*(d.value/max); svg+=`<text x="${m.l-12}" y="${y+bh*.66}" text-anchor="end" font-size="12" fill="#294B70" font-weight="800">${esc(trunc(d.label,34))}</text><rect class="bar" data-tip="${esc(d.label)}: ${fmt.format(Math.round(+d.value||0))}" x="${m.l}" y="${y}" width="${Math.max(w,4)}" height="${bh}" rx="9" fill="url(#barGrad)" filter="url(#softShadow)"/><text x="${Math.min(m.l+w+10,W-48)}" y="${y+bh*.66}" font-size="12" fill="#061A36" font-weight="950">${fmt.format(Math.round(+d.value||0))}</text>`; });
 svg+=`</svg>`; el.innerHTML=svg; bindTips(el);
}
function groupedChart(el,data){
 const W=el.clientWidth||980,H=Math.max(el.clientHeight||360, 130 + (data||[]).length*62); const m={t:32,r:78,b:36,l:230}; const max=Math.max(...data.flatMap(d=>[+d.sucesso||0,+d.semSucesso||0]),1); let svg=`<svg viewBox="0 0 ${W} ${H}" width="100%" height="100%">`;
 svg+=`<text x="${m.l}" y="18" font-size="12" fill="#0057B8" font-weight="950">■ Com sucesso</text><text x="${m.l+130}" y="18" font-size="12" fill="#E05252" font-weight="950">■ Sem sucesso</text>`;
 const rowH=(H-m.t-m.b)/data.length;
 data.forEach((d,i)=>{ const y=m.t+i*rowH+8; svg+=`<text x="${m.l-14}" y="${y+22}" text-anchor="end" font-size="12" fill="#294B70" font-weight="800">${esc(trunc(d.label,28))}</text>`; [['sucesso','#0057B8','Com sucesso',0],['semSucesso','#E05252','Sem sucesso',25]].forEach(arr=>{ const key=arr[0],color=arr[1],lab=arr[2],off=arr[3]; const w=(W-m.l-m.r)*(d[key]/max); const yy=y+off; svg+=`<rect class="bar" data-tip="${esc(d.label)} · ${lab}: ${fmt.format(Math.round(+d[key]||0))}" x="${m.l}" y="${yy}" width="${Math.max(w,4)}" height="18" rx="9" fill="${color}"/><text x="${Math.min(m.l+w+9,W-48)}" y="${yy+13}" font-size="12" fill="#061A36" font-weight="950">${fmt.format(Math.round(+d[key]||0))}</text>`; }); });
 svg+=`</svg>`; el.innerHTML=svg; bindTips(el);
}

function groupedColumnChart(el,data){
 const W=el.clientWidth||980,H=Math.max(el.clientHeight||380,380);
 const m={t:76,r:32,b:88,l:54};
 const defs='<defs><linearGradient id="colGradBlue" x1="0" x2="0" y1="0" y2="1"><stop offset="0" stop-color="#0B7CE6"/><stop offset="1" stop-color="#0057B8"/></linearGradient><linearGradient id="colGradRed" x1="0" x2="0" y1="0" y2="1"><stop offset="0" stop-color="#FF7A7A"/><stop offset="1" stop-color="#E05252"/></linearGradient><filter id="colShadow"><feDropShadow dx="0" dy="4" stdDeviation="4" flood-color="#0A4EA8" flood-opacity=".16"/></filter></defs>';
 const max=Math.max(...(data||[]).flatMap(d=>[+d.sucesso||0,+d.semSucesso||0]),1);
 const innerW=W-m.l-m.r, innerH=H-m.t-m.b;
 const groupW=innerW/Math.max((data||[]).length,1);
 const barW=Math.min(44, groupW*0.22);
 const gap=barW*0.38;
 const pairW=barW*2+gap;
 const x0=i=>m.l+i*groupW + (groupW-pairW)/2;
 const y=v=>H-m.b-(v/max)*innerH;
 let svg=`<svg viewBox="0 0 ${W} ${H}" width="100%" height="100%">${defs}`;
 svg+=`<text x="${m.l+10}" y="22" font-size="12" fill="#0057B8" font-weight="950">■ Com sucesso</text><text x="${m.l+146}" y="22" font-size="12" fill="#E05252" font-weight="950">■ Sem sucesso</text>`;
 // baseline
 svg+=`<line x1="${m.l}" y1="${H-m.b}" x2="${W-m.r}" y2="${H-m.b}" stroke="#D8E4F2" stroke-width="2"/>`;
 (data||[]).forEach((d,i)=>{
   const baseX=x0(i);
   const bars=[
     {key:'sucesso',label:'Com sucesso',color:'url(#colGradBlue)',x:baseX,val:+d.sucesso||0},
     {key:'semSucesso',label:'Sem sucesso',color:'url(#colGradRed)',x:baseX+barW+gap,val:+d.semSucesso||0}
   ];
   bars.forEach(b=>{
     const h=Math.max((b.val/max)*innerH, b.val>0?4:0);
     const yy=H-m.b-h;
     svg+=`<rect class="bar" data-tip="${esc(d.label)} · ${b.label}: ${fmt.format(Math.round(b.val))}" x="${b.x}" y="${yy}" width="${barW}" height="${h}" rx="10" fill="${b.color}" filter="url(#colShadow)"/>`;
     svg+=`<text x="${b.x+barW/2}" y="${Math.max(m.t-8,yy-10)}" text-anchor="middle" font-size="12" fill="#061A36" font-weight="950">${fmt.format(Math.round(b.val))}</text>`;
   });
   const cx=baseX+pairW/2;
   const lines=String(d.label||'').split(' ');
   if(lines.length>1){
     const first=esc(lines.slice(0,-1).join(' '));
     const last=esc(lines.slice(-1).join(' '));
     svg+=`<text x="${cx}" y="${H-m.b+24}" text-anchor="middle" font-size="12" fill="#294B70" font-weight="800">${first}</text>`;
     svg+=`<text x="${cx}" y="${H-m.b+40}" text-anchor="middle" font-size="12" fill="#294B70" font-weight="800">${last}</text>`;
   } else {
     svg+=`<text x="${cx}" y="${H-m.b+28}" text-anchor="middle" font-size="12" fill="#294B70" font-weight="800">${esc(d.label)}</text>`;
   }
 });
 svg+=`</svg>`;
 el.innerHTML=svg; bindTips(el);
}

function lineChart(el,data,expanded=false){
 const W=el.clientWidth||980,H=el.clientHeight||380;
 const m=expanded?{t:74,r:70,b:122,l:68}:{t:34,r:48,b:52,l:58};
 const vals=data.map(d=>+d.value||0); const max=Math.max(...vals,1), min=Math.min(...vals,0); const range=Math.max(max-min,1); const stepX=(W-m.l-m.r)/Math.max(data.length-1,1); const y=v=>H-m.b-((v-min)/range)*(H-m.t-m.b); let pts=data.map((d,i)=>[m.l+i*stepX,y(+d.value||0)]);
 let area=`M ${pts[0][0]} ${H-m.b} L `+pts.map(p=>p.join(' ')).join(' L ')+` L ${pts[pts.length-1][0]} ${H-m.b} Z`; let line='M '+pts.map(p=>p.join(' ')).join(' L ');
 let svg=`<svg viewBox="0 0 ${W} ${H}" width="100%" height="100%"><defs><linearGradient id="area" x1="0" x2="0" y1="0" y2="1"><stop offset="0" stop-color="#0072CE" stop-opacity=".24"/><stop offset="1" stop-color="#0072CE" stop-opacity="0"/></linearGradient></defs>`;
 svg+=`<path d="${area}" fill="url(#area)"/><path d="${line}" fill="none" stroke="#0057B8" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"/>`;
 const step=Math.max(1,Math.ceil(data.length/10));
 data.forEach((d,i)=>{
   const [x,yy]=pts[i]; const show=expanded || i===0||i===data.length-1||i%step===0;
   const r=expanded?4.5:5;
   svg+=`<circle class="bar" data-tip="${esc(d.label)}: ${fmt.format(Math.round(+d.value||0))}" cx="${x}" cy="${yy}" r="${r}" fill="#fff" stroke="#0057B8" stroke-width="3"/>`;
   if(show){
     const valueLabel=expanded?fmt.format(Math.round(+d.value||0)):shortFmt.format(+d.value||0);
     let labelY = yy - (expanded?22:18);
     if(labelY < m.t+14) labelY = yy + (expanded?30:26);
     const labelStyle = expanded ? 'paint-order:stroke;stroke:#fff;stroke-width:7px;stroke-linejoin:round' : 'paint-order:stroke;stroke:#fff;stroke-width:6px;stroke-linejoin:round';
     svg+=`<text x="${x}" y="${Math.max(m.t+12,labelY)}" text-anchor="middle" font-size="${expanded?12:12}" fill="#061A36" font-weight="950" style="${labelStyle}">${valueLabel}</text>`;
     if(expanded){
       svg+=`<text x="${x}" y="${H-34}" text-anchor="end" font-size="11" fill="#61738C" font-weight="850" transform="rotate(-45 ${x} ${H-34})">${esc(d.label)}</text>`;
     } else {
       svg+=`<text x="${x}" y="${H-20}" text-anchor="middle" font-size="10" fill="#61738C" font-weight="800">${esc(d.label)}</text>`;
     }
   }
 });
 svg+=`</svg>`; el.innerHTML=svg; bindTips(el);
}

function excelCell(v){ return String(v??'').replace(/[&<>]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[m])); }
function safeFileName(s){ return String(s||'exportacao').normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-zA-Z0-9_-]+/g,'_').replace(/^_+|_+$/g,'').slice(0,90) || 'exportacao'; }
function chartRowsForExcel(c){
 if(!c || !Array.isArray(c.data)) return {headers:['Indicador','Valor'], rows:[]};
 if(c.type==='groupedBar' || c.type==='groupedColumn'){
   return {headers:['Carteira','Finalizado com sucesso','Finalizado sem sucesso'], rows:c.data.map(d=>[d.label, Math.round(+d.sucesso||0), Math.round(+d.semSucesso||0)])};
 }
 if(c.type==='ufMap'){
   return {headers:['UF','Quantidade'], rows:c.data.map(d=>[d.uf||d.label, Math.round(+d.value||0)])};
 }
 return {headers:['Categoria','Quantidade'], rows:c.data.map(d=>[d.label, Math.round(+d.value||0)])};
}
function exportChartExcel(sheetName,index){
 const s=DATA.sheets.find(x=>x.name===sheetName); if(!s || !s.charts[index]) return;
 const c=s.charts[index]; const pack=chartRowsForExcel(c);
 const title=`${s.name} - ${c.title}`;
 const headerHtml=pack.headers.map(h=>`<th>${excelCell(h)}</th>`).join('');
 const rowsHtml=pack.rows.map(row=>`<tr>${row.map(v=>`<td>${excelCell(v)}</td>`).join('')}</tr>`).join('');
 const html=`<!doctype html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif}table{border-collapse:collapse}th{background:#0057B8;color:#fff;font-weight:bold}th,td{border:1px solid #C9DDF3;padding:8px 10px}h2{color:#061A36}</style></head><body><h2>${excelCell(title)}</h2><p>${excelCell(c.subtitle||'')}</p><table><thead><tr>${headerHtml}</tr></thead><tbody>${rowsHtml}</tbody></table></body></html>`;
 const blob=new Blob(['﻿',html],{type:'application/vnd.ms-excel;charset=utf-8;'});
 const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=`${safeFileName(s.name)}_${safeFileName(c.title)}.xls`; document.body.appendChild(a); a.click(); document.body.removeChild(a); setTimeout(()=>URL.revokeObjectURL(a.href),1000);
}

function openChartModal(sheetName,index){
 const s=DATA.sheets.find(x=>x.name===sheetName); if(!s||!s.charts[index]) return;
 const c=s.charts[index]; modalTitle.textContent=c.title; modalSubtitle.textContent=(s.name+' · '+(c.subtitle||'')).trim(); modalCanvas.innerHTML=''; chartModal.classList.add('open'); chartModal.setAttribute('aria-hidden','false');
 requestAnimationFrame(()=>renderChart(modalCanvas,c,true));
}
closeModal.addEventListener('click',()=>{chartModal.classList.remove('open'); chartModal.setAttribute('aria-hidden','true'); modalCanvas.innerHTML='';});
chartModal.addEventListener('click',e=>{if(e.target===chartModal) closeModal.click();});
document.addEventListener('keydown',e=>{if(e.key==='Escape'&&chartModal.classList.contains('open')) closeModal.click();});
function trunc(s,n){s=String(s); return s.length>n?s.slice(0,n-1)+'…':s;}
function bindTips(el){el.querySelectorAll('.bar').forEach(x=>{x.addEventListener('mousemove',e=>showTip(x.dataset.tip,e.clientX,e.clientY)); x.addEventListener('mouseleave',hideTip);})}

function bytesToSize(bytes){ const n=+bytes||0; if(n<1024) return n+' B'; if(n<1024*1024) return (n/1024).toFixed(1).replace('.',',')+' KB'; return (n/1024/1024).toFixed(1).replace('.',',')+' MB'; }
function getLocalBases(){ try{return JSON.parse(localStorage.getItem(HISTORY_STORAGE_KEY)||'[]')}catch(e){return []} }
function saveLocalBases(items){ try{localStorage.setItem(HISTORY_STORAGE_KEY,JSON.stringify(items));return true}catch(e){alert('Não foi possível salvar esta base localmente. O arquivo pode estar muito grande para o armazenamento do navegador.');return false} }
function getHiddenBases(){ try{return JSON.parse(localStorage.getItem(HISTORY_HIDDEN_KEY)||'[]')}catch(e){return []} }
function saveHiddenBases(items){ localStorage.setItem(HISTORY_HIDDEN_KEY,JSON.stringify(items)); }
function getBaseNameOverrides(){ try{return JSON.parse(localStorage.getItem(HISTORY_NAME_KEY)||'{}')}catch(e){return {}} }
function saveBaseNameOverrides(obj){ localStorage.setItem(HISTORY_NAME_KEY,JSON.stringify(obj||{})); }
function withNameOverrides(items){ const names=getBaseNameOverrides(); return items.map(x=>names[x.id]?{...x,fechamento:names[x.id]}:x); }
function allHistoryBases(){ const hidden=new Set(getHiddenBases()); return withNameOverrides(EMBEDDED_BASES.concat(getLocalBases()).filter(x=>!hidden.has(x.id))); }
function downloadHistoryBase(id){
 const item=allHistoryBases().find(x=>x.id===id); if(!item) return;
 const a=document.createElement('a'); a.href=`data:${item.mime||'application/vnd.ms-excel'};base64,${item.base64}`; a.download=item.nome||'base_fechamento.xlsx'; document.body.appendChild(a); a.click(); document.body.removeChild(a);
}
function removeLocalBase(id){ deleteHistoryBase(id); }
function editHistoryBaseName(id){
 if(!canManageHistory()){ alert('Acesso restrito a administradores.'); return; }
 const item=allHistoryBases().find(x=>x.id===id); if(!item) return;
 const current=item.fechamento||item.nome||'Fechamento';
 const next=prompt('Informe o novo nome de exibição da base:', current);
 if(!next || !next.trim()) return;
 const names=getBaseNameOverrides(); names[id]=next.trim(); saveBaseNameOverrides(names); renderHistoryBases();
}
function deleteHistoryBase(id){
 if(!canManageHistory()){ alert('Acesso restrito a administradores.'); return; }
 const item=allHistoryBases().find(x=>x.id===id); if(!item) return;
 if(id===ACTIVE_HISTORY_ID){ alert('Esta base está em uso no painel. Carregue outra base antes de ocultar ou excluir este item.'); return; }
 const ok=confirm(`Deseja remover a base "${item.fechamento||item.nome}" do histórico?\n\nBases incorporadas ao HTML serão ocultadas neste navegador. Bases locais serão excluídas do armazenamento local.`);
 if(!ok) return;
 const isLocal=!EMBEDDED_BASES.some(x=>x.id===id);
 if(isLocal){ saveLocalBases(getLocalBases().filter(x=>x.id!==id)); }
 else { const hidden=getHiddenBases(); if(!hidden.includes(id)) hidden.push(id); saveHiddenBases(hidden); }
 renderHistoryBases();
}
function renderHistoryBases(){
 document.body.classList.toggle('adminUnlocked', canManageHistory());
 const wrap=document.getElementById('historyList'); if(!wrap) return;
 const items=allHistoryBases();
 if(!items.length){ wrap.innerHTML='<div class="historyEmpty">Nenhuma base disponível no histórico.</div>'; return; }
 wrap.classList.toggle('adminUnlocked', canManageHistory());
 wrap.innerHTML=items.map(item=>{
   const isLocal=!EMBEDDED_BASES.some(x=>x.id===item.id);
   const canLoad=!!EMBEDDED_DASHBOARDS[item.id];
   const isActive=item.id===ACTIVE_HISTORY_ID;
   const loadButton = canLoad
     ? (isActive ? `<button class="baseSelect active" type="button">✓ Em uso no painel</button>` : `<button class="baseSelect" onclick="requestHistoryLoad('${escAttr(item.id)}')">↻ Selecionar painel</button>`)
     : `<button class="baseSelect pending" onclick="requestHistoryLoad('${escAttr(item.id)}')" title="Base disponível no histórico. Para atualizar gráficos, ela precisa ser incorporada em uma nova versão do painel.">↻ Selecionar base</button>`;
   const adminButtons = canManageHistory() ? `<div class="baseAdminActions"><button class="baseEdit" onclick="editHistoryBaseName('${escAttr(item.id)}')">✎ Editar nome</button><button class="baseRemove" onclick="deleteHistoryBase('${escAttr(item.id)}')">Excluir base</button></div>` : '';
   return `<article class="baseCard"><div class="baseTop"><div class="baseFileIcon">XLS</div><div class="baseInfo"><h4>${esc(item.fechamento||'Fechamento')}</h4><p>${esc(item.nome||'Base de fechamento.xlsx')}</p></div></div><div class="baseMeta"><span class="basePill">Data: ${esc(item.data||'Não informada')}</span><span class="basePill">${esc(bytesToSize(item.size))}</span><span class="basePill ${isLocal?'':'available'}">${isLocal?'Base local':'Disponível'}</span></div><div class="baseActions"><button class="baseDownload" onclick="downloadHistoryBase('${escAttr(item.id)}')">⬇ Baixar Excel</button>${loadButton}</div>${adminButtons}</article>`;
 }).join('');
}
function requestHistoryLoad(id){
 const item=allHistoryBases().find(x=>x.id===id); if(!item) return;
 const dashboard=EMBEDDED_DASHBOARDS[id];
 if(!dashboard){
   alert('Esta base está salva no histórico e disponível para download.\n\nPara que ela altere KPIs, gráficos e insights do painel, os dados precisam ser processados e incorporados em uma nova versão do HTML.');
   return;
 }
 const ok=confirm(`Deseja carregar o painel do fechamento "${item.fechamento||item.nome}"?\n\nAo confirmar, todos os KPIs, gráficos e insights serão atualizados para os dados dessa base.`);
 if(!ok) return;
 DATA=JSON.parse(JSON.stringify(dashboard));
 ACTIVE_HISTORY_ID=id;
 buildMenu();
 closeHistory();
 setView('geral');
 setTimeout(()=>alert(`Painel carregado: ${item.fechamento||item.nome}`),80);
}
function openHistory(){ const m=document.getElementById('historyModal'); if(!m) return; document.body.classList.toggle('adminUnlocked', canManageHistory()); renderHistoryBases(); m.classList.add('open'); m.setAttribute('aria-hidden','false'); }
function closeHistory(){ const m=document.getElementById('historyModal'); if(!m) return; m.classList.remove('open'); m.setAttribute('aria-hidden','true'); }
function openAdvancedSettings(){ if(!canManageHistory()){ alert('Acesso restrito a administradores.'); return; } const m=document.getElementById('advancedModal'); if(!m) return; const input=document.getElementById('advancedPassword'); if(input) input.value=''; m.classList.add('open'); m.setAttribute('aria-hidden','false'); setTimeout(()=>input&&input.focus(),80); }
function closeAdvancedSettings(){ const m=document.getElementById('advancedModal'); if(!m) return; m.classList.remove('open'); m.setAttribute('aria-hidden','true'); }
function unlockAdvancedSettings(){
 if(!canManageHistory()){ alert('Acesso restrito a administradores.'); return; }
 const input=document.getElementById('advancedPassword'); const value=input?input.value:'';
 if(value==='Tmch@2026'){
   ADMIN_UNLOCKED=true;
   document.body.classList.add('adminUnlocked');
   closeAdvancedSettings();
   renderHistoryBases();
 } else {
   alert('Senha inválida. Verifique a senha e tente novamente.');
   if(input){ input.focus(); input.select(); }
 }
}
function setupHistoryModal(){
 const openBtn=document.getElementById('openHistoryBtn'), closeBtn=document.getElementById('closeHistoryModal'), modal=document.getElementById('historyModal'), fileInput=document.getElementById('historyFileInput');
 const advBtn=document.getElementById('advancedSettingsBtn'), advModal=document.getElementById('advancedModal'), advClose=document.getElementById('closeAdvancedModal'), unlockBtn=document.getElementById('unlockAdvancedBtn'), passInput=document.getElementById('advancedPassword');
 if(openBtn) openBtn.addEventListener('click',openHistory);
 if(closeBtn) closeBtn.addEventListener('click',closeHistory);
 if(modal) modal.addEventListener('click',e=>{if(e.target===modal) closeHistory();});
 if(advBtn) advBtn.addEventListener('click',openAdvancedSettings);
 if(advClose) advClose.addEventListener('click',closeAdvancedSettings);
 if(unlockBtn) unlockBtn.addEventListener('click',unlockAdvancedSettings);
 if(advModal) advModal.addEventListener('click',e=>{if(e.target===advModal) closeAdvancedSettings();});
 if(passInput) passInput.addEventListener('keydown',e=>{if(e.key==='Enter') unlockAdvancedSettings();});
 if(fileInput) fileInput.addEventListener('change',e=>{
   if(!canManageHistory()){ alert('Acesso restrito a administradores.'); e.target.value=''; return; }
   const file=e.target.files && e.target.files[0]; if(!file) return;
   const reader=new FileReader();
   reader.onload=()=>{
     const result=String(reader.result||''); const base64=result.split(',')[1]||'';
     const label=prompt('Informe o mês/ano desta base:', file.name.replace(/\.(xlsx|xls)$/i,'')) || file.name.replace(/\.(xlsx|xls)$/i,'');
     const item={id:'local-'+Date.now(),fechamento:label,nome:file.name,data:new Date().toLocaleDateString('pt-BR'),size:file.size,mime:file.type||'application/vnd.ms-excel',base64};
     const items=getLocalBases(); items.unshift(item); if(saveLocalBases(items)) renderHistoryBases();
   };
   reader.readAsDataURL(file); e.target.value='';
 });
}

initAuth();
buildMenu();
setupHistoryModal();
setView('geral');
function setView(key){ key==='geral'?generalView():nucleoView(key); window.scrollTo({top:0,behavior:'smooth'}); }
window.addEventListener('resize',()=>{ const key=currentViewKey || 'geral'; key==='geral'?generalView():nucleoView(key); });
